toolCalls.args:
{"command": "# Try to find the debug info files with different URL patterns
for lib in libmonosgen-2.0.so libSystem.Native.so libSystem.Globalization.Native.so; do
  case "$lib" in
    libmonosgen-2.0.so) bid="1eb39fc72918c7c6c0c610b79eb3d3d47b2f81be" ;;
    libSystem.Native.so) bid="7a3b5c9d1e4f6082a3c5d7e9f1b2d4a6c8e0f213" ;;
    libSystem.Globalization.Native.so) bid="2f4a6b8c0d2e4f6a8c0e2f4a6b8c0d2e4f6a8c0e" ;;
  esac

  # Try .dbg variant
  curl -sSL -o /dev/null \
    "https://msdl.microsoft.com/download/symbols/${lib}.dbg/elf-buildid-${bid}/${lib}.dbg" \
    -w "${lib}.dbg: HTTP %{http_code}\n"
done", "description": "Try .dbg debug info files", "initial_wait": 15}

arguments.command:
# Check if there are dynamic symbols we can use for lookup
readelf --dyn-syms /tmp/symbols/mono.so 2>/dev/null | wc -l
echo "---"
# Use nm to extract dynamic symbols and manually match addresses
# The addresses from the tombstone:
# #01 pc 0x222098, #02 pc 0x222234, #03 pc 0x19bac0, #06 pc 0x19bc14

# Find the nearest symbol for each address
for addr in 222098 222234 19bac0 19bc14; do
  echo "=== 0x$addr ==="
  # Get all dynamic symbols, sort by address, find the nearest one <= our address
  readelf --dyn-syms /tmp/symbols/mono.so 2>/dev/null | awk -v target="0x$addr" '
    NR>3 && $2!="0000000000000000" && $4=="FUNC" {
      addr = strtonum("0x" $2)
      tgt = strtonum(target)
      if (addr <= tgt && addr > best_addr) {
        best_addr = addr
        best_name = $NF
        best_size = strtonum("0x" $3)
        offset = tgt - addr
      }
    }
    END {
      if (best_name != "") {
        printf "  %s+0x%x", best_name, offset
        if (offset < best_size) printf " (in function)"
        printf "\n"
      } else {
        print "  ??"
      }
    }'
done

